import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { WatchlistItem, WatchlistService } from '../../services/watchlist.service';

@Component({
  selector: 'app-watchlist',
  standalone: true,
  imports: [CommonModule, NavbarComponent],
  templateUrl: './watchlist.component.html',
  styleUrl: './watchlist.component.css'
})
export class WatchlistComponent implements OnInit {
  items: WatchlistItem[] = [];
  loading = true;
  error: string | null = null;

  constructor(
    private watchlistService: WatchlistService,
    private router: Router
  ) {}

  ngOnInit() {
    this.loadWatchlist();
  }

  loadWatchlist() {
    this.loading = true;
    this.watchlistService.getWatchlist().subscribe({
      next: (items) => {
        this.items = items;
        this.loading = false;
      },
      error: () => {
        this.error = 'Failed to load watchlist';
        this.loading = false;
      }
    });
  }

  removeFromWatchlist(movieId: number) {
    this.watchlistService.removeFromWatchlist(movieId).subscribe({
      next: () => this.loadWatchlist(),
      error: () => this.error = 'Failed to remove movie'
    });
  }

  writeReview(movieId: number) {
    this.router.navigate(['/create-review'], { queryParams: { movieId } });
  }

  browseMovies() {
    this.router.navigate(['/movies']);
  }
}
<div class="page-container">
  <app-navbar></app-navbar>

  <div class="page-content">
    <div class="page-header">
      <h1>My Watchlist</h1>
      <button class="btn btn-secondary" (click)="browseMovies()">Browse Movies</button>
    </div>

    <div *ngIf="loading" class="loading">Loading watchlist...</div>
    <div *ngIf="error" class="error-message">{{ error }}</div>

    <div *ngIf="!loading && items.length === 0" class="empty-state">
      <p>Your watchlist is empty.</p>
      <button class="btn btn-primary" (click)="browseMovies()">Discover Movies</button>
    </div>

    <div *ngIf="!loading && items.length > 0" class="movie-grid">
      <div *ngFor="let item of items" class="movie-card">
        <img *ngIf="item.movieImage" [src]="item.movieImage" [alt]="item.movieTitle" class="movie-poster" />
        <div *ngIf="!item.movieImage" class="movie-poster placeholder">🎬</div>
        <div class="movie-info">
          <h3>{{ item.movieTitle }}</h3>
          <small>Added {{ item.dateAdded | date:'mediumDate' }}</small>
          <div class="card-actions">
            <button class="btn btn-primary btn-sm" (click)="writeReview(item.movieId)">Review</button>
            <button class="btn btn-danger btn-sm" (click)="removeFromWatchlist(item.movieId)">Remove</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
